import React, { useState, useEffect } from 'react';
import './App.css';
import Terminal from './Terminal';

const App = () => {
  const [activeApp, setActiveApp] = useState(null);

  useEffect(() => {
    const handleScroll = () => {
      const taskbar = document.querySelector('.taskbar');
      const taskbarApps = document.querySelectorAll('.taskbar-app');
      const scrollY = window.scrollY;

      if (scrollY >= 300) {
        taskbar.classList.add('taskbar-visible');
        taskbarApps.forEach((app, index) => {
          app.style.transitionDelay = `${index * 0.1}s`;
          app.classList.add('taskbar-app-visible');
        });
      } else {
        taskbar.classList.remove('taskbar-visible');
        taskbarApps.forEach((app) => {
          app.style.transitionDelay = '0s';
          app.classList.remove('taskbar-app-visible');
        });
      }
    };

    window.addEventListener('scroll', handleScroll);

    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  const handleBoxClick = (boxName) => {
    setActiveApp(boxName);
  };

  return (
    <div className="App">
      <header className="App-header">
        <Terminal activeApp={activeApp} />
        <div className="box-container">
          <div
            className={`box ${activeApp === 'box1' ? 'active' : ''}`}
            onClick={() => handleBoxClick('box1')}
          >
            <div className="box-content">
              <h3>Box 1</h3>
              <p>Sample text for Box 1</p>
            </div>
          </div>
          <div
            className={`box ${activeApp === 'box2' ? 'active' : ''}`}
            onClick={() => handleBoxClick('box2')}
          >
            <div className="box-content">
              <h3>Box 2</h3>
              <p>Sample text for Box 2</p>
            </div>
          </div>
          <div
            className={`box ${activeApp === 'box3' ? 'active' : ''}`}
            onClick={() => handleBoxClick('box3')}
          >
            <div className="box-content">
              <h3>Box 3</h3>
              <p>Sample text for Box 3</p>
            </div>
          </div>
        </div>
      </header>
    </div>
  );
};

export default App;
